boot.artifact:
// 先挂 iframe，再动态载入较大的 render 依赖图；网络冷启动时容器也不会被判空
const frame = document.createElement('iframe'); frame.style.cssText = `width:100%;height:${spec.height ?? 640}px;border:0`; frame.srcdoc = '<p style="font:14px system-ui">Rendering email preview…</p>'; document.getElementById('email').appendChild(frame);
const { render } = await import('https://cdn.jsdelivr.net/npm/@react-email/components@1.0.12/+esm');
frame.srcdoc = await render(data.email, data.render_options ?? {});

